  finish?: string;
  price?: number;
  imageUrl?: string;
  diameter?: string;
  width?: string;
  boltPattern?: string;
  offset?: string;
  staggered?: boolean;
  rearSku?: string;
  rearDiameter?: string;
  rearWidth?: string;
  rearOffset?: string;
};

