"use client";

import Image from "next/image";
import Link from "next/link";
import { Suspense, useState } from "react";
import { useSearchParams } from "next/navigation";
import { BRAND } from "@/lib/brand";
// FitmentSelector now lives inside the search modal / mega menu flow
import { SearchModal, type Mode } from "@/components/SearchModal";
import { MegaMenu } from "@/components/MegaMenu";

function PillLink({ href, children }: { href: string; children: React.ReactNode }) {
  return (
    <a
      href={href}
      className="inline-flex items-center justify-center rounded-full border border-neutral-200 bg-white px-3 py-1.5 text-sm font-semibold text-neutral-900 hover:bg-neutral-50"
    >
      {children}
    </a>
  );
}

function withFitmentParams(href: string, sp: URLSearchParams) {
  const next = new URLSearchParams(sp.toString());
  const qs = next.toString();
  return qs ? `${href}?${qs}` : href;
}

function FitmentLink({
  href,
  className,
  children,
  disabled,
}: {
  href: string;
  className: string;
  children: React.ReactNode;
  disabled?: boolean;
}) {
  const sp = useSearchParams();
  const target = withFitmentParams(href, sp);
  if (disabled) {
    return (
      <span className={`${className} pointer-events-none opacity-50`}>
        {children}
      </span>
    );
  }
  return (
    <Link href={target} className={className}>
      {children}
    </Link>
  );
}

function hasVehicle(sp: URLSearchParams) {
  return !!(sp.get("year") && sp.get("make") && sp.get("model"));
}

function FitmentTabs() {
  const sp = useSearchParams();
  const enabled = hasVehicle(sp);

  const base = "inline-flex h-11 items-center justify-center rounded-xl px-4 text-sm font-extrabold";
  const pill = "border border-neutral-200 bg-white text-neutral-900 hover:bg-neutral-50";
  const active = "bg-[var(--brand-red)] text-white hover:bg-[var(--brand-red-700)]";

  const path = typeof window !== "undefined" ? window.location.pathname : "";
  const isTires = path.startsWith("/tires");
  const isWheels = path.startsWith("/wheels");

  return (
    <div className="grid grid-cols-3 gap-2">
      <FitmentLink
        href="/tires"
        disabled={!enabled}
        className={`${base} ${isTires ? active : pill}`}
      >
        Tires
      </FitmentLink>
      <FitmentLink
        href="/wheels"
        disabled={!enabled}
        className={`${base} ${isWheels ? active : pill}`}
      >
        Wheels
      </FitmentLink>
      <span className={`${base} ${pill} pointer-events-none opacity-50`}>
        Packages
      </span>
    </div>
  );
}

export function Header() {
  const [modal, setModal] = useState<null | { type: "tires" | "wheels"; mode?: Mode }>(null);

  return (
    <header className="sticky top-0 z-50 border-b border-neutral-200 bg-white/95 backdrop-blur">
      <div className="mx-auto flex max-w-6xl flex-col gap-3 px-4 py-3 md:flex-row md:items-center md:gap-6">
        <Link href="/" className="flex items-center gap-2">
          <Image
            src="/warehouse-tire-logo.jpg"
            alt={BRAND.name}
            width={220}
            height={58}
            priority
            className="h-12 w-auto"
          />
        </Link>

        {/* Desktop selector removed in favor of DiscountTire-style mega menu */}

        {/* Mobile: use tap-based modals via the action bar / simple buttons below */}
        <div className="w-full md:hidden">
          <div className="grid grid-cols-2 gap-2">
            <button
              type="button"
              onClick={() => setModal({ type: "tires", mode: "vehicle" })}
              className="h-11 rounded-xl border border-neutral-200 bg-white px-3 text-sm font-extrabold text-neutral-900"
            >
              Tires
            </button>
            <button
              type="button"
              onClick={() => setModal({ type: "wheels", mode: "vehicle" })}
              className="h-11 rounded-xl border border-neutral-200 bg-white px-3 text-sm font-extrabold text-neutral-900"
            >
              Wheels
            </button>
          </div>
        </div>

        <nav className="hidden items-center gap-4 md:flex">
          <MegaMenu
            onOpenSearch={(type, mode) => {
              setModal({ type, mode });
            }}
          />

          <button
            type="button"
            onClick={() => setModal({ type: "wheels", mode: "vehicle" })}
            className="inline-flex items-center justify-center rounded-full border border-neutral-200 bg-white px-4 py-2 text-sm font-extrabold text-neutral-900 hover:bg-neutral-50"
          >
            My Garage
          </button>

          <PillLink href={BRAND.links.tel}>Call</PillLink>
          <Link
            href="/schedule"
            className="inline-flex items-center justify-center rounded-full bg-[var(--brand-red)] px-4 py-2 text-sm font-extrabold text-white hover:bg-[var(--brand-red-700)]"
          >
            Schedule Install
          </Link>
        </nav>
      </div>

      <SearchModal
        open={modal?.type === "tires"}
        type="tires"
        defaultMode={modal?.type === "tires" ? modal.mode : undefined}
        onClose={() => setModal(null)}
      />
      <SearchModal
        open={modal?.type === "wheels"}
        type="wheels"
        defaultMode={modal?.type === "wheels" ? modal.mode : undefined}
        onClose={() => setModal(null)}
      />
    </header>
  );
}

"use client";

import Link from "next/link";
import { useEffect, useRef, useState } from "react";

export function MegaMenu({
  onOpenSearch,
}: {
  onOpenSearch: (type: "tires" | "wheels", mode: "vehicle" | "size") => void;
}) {
  const [open, setOpen] = useState<null | "tires" | "wheels">(null);
  const closeTimer = useRef<number | null>(null);

  function closeNow() {
    if (closeTimer.current) window.clearTimeout(closeTimer.current);
    closeTimer.current = null;
    setOpen(null);
  }

  function scheduleClose() {
    if (closeTimer.current) window.clearTimeout(closeTimer.current);
    closeTimer.current = window.setTimeout(() => setOpen(null), 120);
  }

  function cancelClose() {
    if (closeTimer.current) window.clearTimeout(closeTimer.current);
    closeTimer.current = null;
  }

  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (e.key === "Escape") closeNow();
    }
    function onClick(e: MouseEvent) {
      // close when clicking outside the panel/trigger area
      const el = e.target as HTMLElement | null;
      if (!el) return;
      if (el.closest('[data-megamenu-root="1"]')) return;
      closeNow();
    }

    window.addEventListener("keydown", onKey);
    window.addEventListener("click", onClick);

    return () => {
      window.removeEventListener("keydown", onKey);
      window.removeEventListener("click", onClick);
      if (closeTimer.current) window.clearTimeout(closeTimer.current);
    };
  }, []);

  function Trigger({ type, label }: { type: "tires" | "wheels"; label: string }) {
    const active = open === type;
    return (
      <button
        onMouseEnter={() => {
          cancelClose();
          setOpen(type);
        }}
        onMouseLeave={() => scheduleClose()}
        onFocus={() => setOpen(type)}
        className={
          active
            ? "inline-flex items-center gap-1 border-b-2 border-[var(--brand-red)] px-2 py-2 text-sm font-extrabold text-neutral-900"
            : "inline-flex items-center gap-1 border-b-2 border-transparent px-2 py-2 text-sm font-extrabold text-neutral-900 hover:border-neutral-200"
        }
        type="button"
        aria-haspopup="menu"
        aria-expanded={active}
      >
        {label}
        <span className="text-xs">▾</span>
      </button>
    );
  }

  function Panel({ type }: { type: "tires" | "wheels" }) {
    const isTires = type === "tires";
    return (
      <div
        onMouseEnter={() => cancelClose()}
        onMouseLeave={() => scheduleClose()}
        className="fixed left-0 right-0 top-[72px] z-[70] border-b border-neutral-200 bg-white shadow-xl"
        role="menu"
      >
        <div className="mx-auto grid max-w-6xl gap-6 px-4 py-6 md:grid-cols-[200px_1fr]">
          {/* Left action rail (DiscountTire-style) */}
          <div className="grid gap-2">
            <button
              type="button"
              onClick={() => {
                closeNow();
                onOpenSearch(type, "vehicle");
              }}
              className="h-12 rounded-xl bg-neutral-100 px-3 text-left text-xs font-extrabold text-neutral-900 hover:bg-neutral-200"
            >
              SHOP BY VEHICLE
            </button>
            <button
              type="button"
              onClick={() => {
                closeNow();
                onOpenSearch(type, "size");
              }}
              className="h-12 rounded-xl bg-neutral-100 px-3 text-left text-xs font-extrabold text-neutral-900 hover:bg-neutral-200"
            >
              SHOP BY SIZE
            </button>
            <Link
              href={isTires ? "/tires" : "/wheels"}
              onClick={() => closeNow()}
              className="h-12 rounded-xl bg-neutral-100 px-3 text-left text-xs font-extrabold text-neutral-900 hover:bg-neutral-200 flex items-center"
            >
              SHOP {isTires ? "TIRES" : "WHEELS"}
            </Link>
          </div>

          {/* Right columns (placeholder quick links like the screenshots) */}
          <div className="grid gap-6 md:grid-cols-3">
            <div>
              <div className="text-xs font-extrabold text-neutral-900">
                {isTires ? "TIRE BRAND" : "WHEEL BRAND"}
              </div>
              <div className="mt-3 grid gap-2 text-sm text-neutral-700">
                <span className="opacity-70">(Coming soon)</span>
              </div>
              <div className="mt-3">
                <Link href={isTires ? "/tires" : "/wheels"} className="text-sm font-extrabold text-blue-700 hover:underline">
                  View All
                </Link>
              </div>
            </div>

            <div>
              <div className="text-xs font-extrabold text-neutral-900">
                {isTires ? "TIRE TYPE" : "WHEEL STYLE"}
              </div>
              <div className="mt-3 grid gap-2 text-sm text-neutral-700">
                <span className="opacity-70">(Coming soon)</span>
              </div>
              <div className="mt-3">
                <Link href={isTires ? "/tires" : "/wheels"} className="text-sm font-extrabold text-blue-700 hover:underline">
                  View All
                </Link>
              </div>
            </div>

            <div>
              <div className="text-xs font-extrabold text-neutral-900">VEHICLE TYPE</div>
              <div className="mt-3 grid gap-2 text-sm text-neutral-700">
                <span className="opacity-70">(Coming soon)</span>
              </div>
              <div className="mt-3">
                <Link href={isTires ? "/tires" : "/wheels"} className="text-sm font-extrabold text-blue-700 hover:underline">
                  View All
                </Link>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="relative" data-megamenu-root="1">
      <div className="flex items-center gap-4">
        <Trigger type="tires" label="TIRES" />
        <Trigger type="wheels" label="WHEELS" />
        <Link href="/schedule" className="px-2 py-2 text-sm font-extrabold text-neutral-900 hover:underline">
          SCHEDULE
        </Link>
      </div>

      {open ? <Panel type={open} /> : null}
    </div>
  );
