// Navigate based on entry mode
if (mode === "tires") {
  router.push(`/tires?${qs.toString()}`);
  return;
}
if (mode === "wheels") {
  router.push(`/wheels?${qs.toString()}`);
  return;
}

// Vehicles: default to wheels workspace for now
