() => {
  const pickText = (el) => el ? el.textContent.trim().replace(/\s+/g,' ') : null;
  const h1 = document.querySelector('h1');
  const sku = pickText(document.querySelector('[itemprop="sku"], .sku, .product-sku, .product_meta .sku'));
  const title = pickText(h1) || document.title;
  const ogImg = document.querySelector('meta[property="og:image"]')?.getAttribute('content') || null;
  const desc = document.querySelector('[itemprop="description"], .woocommerce-product-details__short-description, .product-summary, .product-description');
  const description = pickText(desc);
  const specs = {};
  const rows = document.querySelectorAll('table tr');
  for (const tr of rows) {
    const th = tr.querySelector('th,td');
    const tds = tr.querySelectorAll('td');
    if (tds.length >= 2) {
      const k = pickText(tds[0]);
      const v = pickText(tds[1]);
      if (k && v) specs[k] = v;
    }
  }
  const images = Array.from(document.querySelectorAll('img')).map(img => img.currentSrc || img.src).filter(Boolean);
  const mainImages = Array.from(new Set(images.filter(u => /wp-content|uploads|cdn|cloudfront/i.test(u)).slice(0, 10)));
  return { title, sku, description, ogImg, specsCount: Object.keys(specs).length, specs, mainImages: mainImages.slice(0,5), url: location.href };
}

